// ============================================================
// EXTRACT STATUS CHANGE EVENT FROM JIRA MAIN WEBHOOK
// ============================================================
const body = $input.item.json.body || $input.item.json;
const issue = body.issue || {};
const fields = issue.fields || {};
const changelog = body.changelog || {};
const changelogItems = changelog.items || [];

const key = issue.key || '';
const projectKey = (fields.project && fields.project.key) || key.split('-')[0];

// Only process AM project
if (projectKey !== 'AM') {
  return [{ json: { skip: true, reason: 'Not an AM ticket', key } }];
}

// Find the status change item
const statusChange = changelogItems.find(item => item.field === 'status');
if (!statusChange) {
  return [{ json: { skip: true, reason: 'No status change found', key } }];
}

const fromStatus = statusChange.fromString || '';
const toStatus = statusChange.toString || '';
const changedAt = body.timestamp
  ? new Date(body.timestamp).toISOString().split('T')[0]
  : new Date().toISOString().split('T')[0];

const summary = fields.summary || '';
const issueType = (fields.issuetype && fields.issuetype.name) || '';
const assignee = (fields.assignee && fields.assignee.displayName) || '';
const jiraUrl = `https://arduasolutions.atlassian.net/browse/${key}`;

let tipo = 'Story';
if (['Task', 'Sub-task'].includes(issueType)) tipo = 'Task IT';
else if (issueType === 'Epic') tipo = 'Epic';

const getResponsable = (status) => ['Done', 'DEPRECATED'].includes(status) ? 'Ninguno' : 'IT';

const statusToEnteredField = {
  'Backlog':        'Entered Backlog',
  'TO REFINEMENT':  'Entered TO REFINEMENT',
  'IN REFINEMENT':  'Entered IN REFINEMENT',
  'To Do':          'Entered To Do',
  'In Progress':    'Entered In Progress',
  'STAND BY':       'Entered STAND BY',
  'CODE REVIEW':    'Entered CODE REVIEW',
  'Done':           'Entered Done',
  'DEPRECATED':     'Entered DEPRECATED'
};

const statusToDaysField = {
  'Backlog':        'Days in Backlog',
  'TO REFINEMENT':  'Days in TO REFINEMENT',
  'IN REFINEMENT':  'Days in IN REFINEMENT',
  'To Do':          'Days in To Do',
  'In Progress':    'Days in In Progress',
  'STAND BY':       'Days in STAND BY',
  'CODE REVIEW':    'Days in CODE REVIEW',
  'Done':           'Days in Done',
  'DEPRECATED':     'Days in DEPRECATED'
};

return [{
  json: {
    skip: false,
    key,
    summary,
    tipo,
    fromStatus,
    toStatus,
    changedAt,
    assignee,
    jiraUrl,
    responsableFrom: getResponsable(fromStatus),
    responsableTo: getResponsable(toStatus),
    enteredFieldTo: statusToEnteredField[toStatus] || null,
    daysFieldFrom: statusToDaysField[fromStatus] || null
  }
}];

// ============================================================
// CALCULATE DAYS IN PREVIOUS STATUS & BUILD PAYLOADS
// ============================================================
const notionResults = $input.item.json.results || [];
const extract = $('Extract Status Change').item.json;

if (notionResults.length === 0) {
  return [{ json: { skip: true, reason: 'Ticket not found in Notion', key: extract.key } }];
}

const page = notionResults[0];
const pageId = page.id;
const props = page.properties || {};

// Get fecha entrada of the FROM status
const statusToEnteredField = {
  'Backlog':        'Entered Backlog',
  'TO REFINEMENT':  'Entered TO REFINEMENT',
  'IN REFINEMENT':  'Entered IN REFINEMENT',
  'To Do':          'Entered To Do',
  'In Progress':    'Entered In Progress',
  'STAND BY':       'Entered STAND BY',
  'CODE REVIEW':    'Entered CODE REVIEW',
  'Done':           'Entered Done',
  'DEPRECATED':     'Entered DEPRECATED'
};

const statusToDaysField = {
  'Backlog':        'Days in Backlog',
  'TO REFINEMENT':  'Days in TO REFINEMENT',
  'IN REFINEMENT':  'Days in IN REFINEMENT',
  'To Do':          'Days in To Do',
  'In Progress':    'Days in In Progress',
  'STAND BY':       'Days in STAND BY',
  'CODE REVIEW':    'Days in CODE REVIEW',
  'Done':           'Days in Done',
  'DEPRECATED':     'Days in DEPRECATED'
};

// Calculate days in fromStatus
const fromFechaKey = statusToEnteredField[extract.fromStatus];
let diasEnEstadoAnterior = 0;
let fechaEntradaAnterior = extract.changedAt;

if (fromFechaKey && props[fromFechaKey] && props[fromFechaKey].date && props[fromFechaKey].date.start) {
  fechaEntradaAnterior = props[fromFechaKey].date.start;
  const fechaEntrada = new Date(fechaEntradaAnterior);
  const fechaSalida = new Date(extract.changedAt);
  const diffMs = fechaSalida - fechaEntrada;
  diasEnEstadoAnterior = Math.max(0, Math.round((diffMs / (1000 * 60 * 60 * 24)) * 10) / 10);
}

// Build update properties for SLA — Tickets MAIN
const updateProperties = {
  'Current Status': { select: { name: extract.toStatus } },
  'Flow':           { select: { name: extract.responsableTo } },
  'IT Flow?':       { checkbox: extract.responsableTo === 'IT' },
  'Last Updated':   { date: { start: extract.changedAt } },
  'Days in Current Status': { number: 0 }
};

// Update dias en fromStatus
const diasFromKey = statusToDaysField[extract.fromStatus];
if (diasFromKey) {
  updateProperties[diasFromKey] = { number: diasEnEstadoAnterior };
}

// Set fecha entrada for toStatus
const fechaToKey = statusToEnteredField[extract.toStatus];
if (fechaToKey) {
  updateProperties[fechaToKey] = { date: { start: extract.changedAt } };
}

// Build changelog entry
const transitionId = `${extract.key}-${extract.fromStatus}-${extract.toStatus}-${extract.changedAt}`;

const changelogProperties = {
  'Transition ID':         { title: [{ text: { content: transitionId } }] },
  'Ticket Key':            { rich_text: [{ text: { content: extract.key } }] },
  'Type':                  { select: { name: extract.tipo } },
  'Previous Status':       { rich_text: [{ text: { content: extract.fromStatus } }] },
  'New Status':            { rich_text: [{ text: { content: extract.toStatus } }] },
  'Previous Status Owner': { select: { name: extract.responsableFrom } },
  'New Status Owner':      { select: { name: extract.responsableTo } },
  'Entry Date':            { date: { start: fechaEntradaAnterior } },
  'Exit Date':             { date: { start: extract.changedAt } },
  'Days in Status':        { number: diasEnEstadoAnterior },
  'Jira URL':              { url: extract.jiraUrl }
};

return [{
  json: {
    skip: false,
    pageId,
    updateProperties,
    changelogProperties,
    key: extract.key
  }
}];
